mapper.insert:
INSERT INTO POINT_HIST (USER_ID, HIST_TYPE, CHANGE_AMT, ORD_SN, MEMO, ASSET_TYPE)
SELECT #{dto.userId}, #{dto.histType}, #{dto.changeAmt}, #{dto.ordSn}, #{dto.memo}, #{assetType}
FROM DUAL
WHERE (
    SELECT NVL(SUM(ph.CHANGE_AMT), 0)
    FROM POINT_HIST ph
    WHERE ph.USER_ID = #{dto.userId}
      AND (
        (ph.MCPNT_SN IS NOT NULL AND EXISTS (
            SELECT 1 FROM MEMBER_COUPONPOINT mcp
             WHERE mcp.MCPNT_SN = ph.MCPNT_SN
               AND mcp.ASSET_TYPE = #{assetType}
        ))
        OR
        (ph.MCPNT_SN IS NULL AND ph.ASSET_TYPE = #{assetType})
      )
) + #{dto.changeAmt} >= 0

mapper.select:
SELECT * FROM ( SELECT m.USER_ID AS "userId", m.USER_NAME AS "userName", m.USER_ROLE AS "userRole", NVL((SELECT SUM(ph.CHANGE_AMT) FROM POINT_HIST ph JOIN MEMBER_COUPONPOINT mcp ON ph.MCPNT_SN = mcp.MCPNT_SN WHERE ph.USER_ID = m.USER_ID AND mcp.ASSET_TYPE = #{assetType}), 0) AS "balance" FROM MEMBER m WHERE m.USER_ROLE IN ('ROLE_USER', 'ROLE_STUDENT') AND m.ENABLE = 'Y'
AND (UPPER(m.USER_ID) LIKE '%' || UPPER(#{q}) || '%' OR UPPER(m.USER_NAME) LIKE '%' || UPPER(#{q}) || '%')
AND m.USER_ROLE = #{role}
) ORDER BY "balance" DESC, "userId"
